"""
appcon4.py — Hybrid Prompt + RAG Tool UI
=========================================
Architecture changes from appcon3:
  • Model selection panel now shows general LLM providers
    (OpenAI, Anthropic, Gemini) with concrete model lists — no "specialized
    domain model" dropdowns.
  • A new "Domain" selector injects domain context via the backend's system
    prompt mechanism (Legal, Medical, Finance, Code, …).
  • The pipeline tab is replaced by a cleaner "LLM + Domain" configuration.
  • Chat payload sends: provider, model_name, domain (instead of category /
    assistant_name / pipeline_role / routing_strategy).
  • All upload, retrieval, agent, and session features are preserved.
"""

import os
import requests
import json
import uuid
import logging
from datetime import datetime
from flask import Flask, render_template_string, request, jsonify, session
from dotenv import load_dotenv

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

load_dotenv()
API_URL = os.getenv("API_URL", "http://127.0.0.1:8000").strip()

app = Flask(__name__)
app.secret_key = os.getenv("SECRET_KEY", "hybrid-rag-tool-secret-2025")


# ─────────────────────────────────────────────────────────────────────────────
# Backend helpers
# ─────────────────────────────────────────────────────────────────────────────

def get_or_create_session():
    if "session_id" not in session:
        session["session_id"] = str(uuid.uuid4())
    return session["session_id"]


def api(endpoint: str) -> str:
    return f"{API_URL.rstrip('/')}/{endpoint.lstrip('/')}/"


def fetch_providers():
    """Fetch general providers + domains from the new /models/ endpoint."""
    try:
        resp = requests.get(api("models"), timeout=10)
        if resp.status_code == 200:
            return resp.json()
    except Exception as e:
        logger.error(f"Error fetching providers: {e}")
    return _default_providers()


def _default_providers():
    return {
        "providers": {
            "openai":    {"gpt-4o": {"label": "GPT-4o", "cost": "$0.005/1K"},
                          "gpt-4-turbo": {"label": "GPT-4 Turbo", "cost": "$0.01/1K"},
                          "gpt-3.5-turbo": {"label": "GPT-3.5 Turbo", "cost": "$0.001/1K"}},
            "anthropic": {"claude-opus-4-5": {"label": "Claude Opus 4.5", "cost": "$0.015/1K"},
                          "claude-sonnet-4-5": {"label": "Claude Sonnet 4.5", "cost": "$0.003/1K"},
                          "claude-3-5-haiku-20241022": {"label": "Claude 3.5 Haiku", "cost": "$0.0008/1K"}},
            "gemini":    {"gemini-1.5-pro": {"label": "Gemini 1.5 Pro", "cost": "$0.007/1K"},
                          "gemini-1.5-flash": {"label": "Gemini 1.5 Flash", "cost": "$0.0007/1K"},
                          "gemini-pro": {"label": "Gemini Pro", "cost": "$0.0005/1K"}},
        },
        "domains": ["General","Legal","Medical","Finance","Code",
                    "Science","Creative","Customer Service","Vision"],
        "architecture": "hybrid_prompt_rag_tool"
    }


# ─────────────────────────────────────────────────────────────────────────────
# Flask API proxy routes
# ─────────────────────────────────────────────────────────────────────────────

@app.route("/api/session/new", methods=["POST"])
def new_session():
    session["session_id"] = str(uuid.uuid4())
    return jsonify({"session_id": session["session_id"]})


@app.route("/api/models", methods=["GET"])
def get_models():
    return jsonify(fetch_providers())


@app.route("/api/chat", methods=["POST"])
def chat():
    data       = request.json or {}
    query      = data.get("query", "")
    session_id = get_or_create_session()
    provider   = data.get("provider", "openai")
    model_name = data.get("model_name", "gpt-4o")
    domain     = data.get("domain", "General")
    top_k      = data.get("top_k", 8)
    use_reranker      = data.get("use_reranker", False)
    use_query_rewriter = data.get("use_query_rewriter", False)
    agent_mode = data.get("agent_mode", False)
    content_types = data.get("content_types", ["text","image","audio","video"])

    if not query:
        return jsonify({"error": "No query provided"}), 400

    # Resolve user API key and namespace from session
    user        = session.get("user", {})
    namespace   = user.get("namespace") or None

    # Resolve user API key from session
    key_map = {"openai":"openai","anthropic":"anthropic","claude":"anthropic",
               "gemini":"gemini","google":"gemini"}
    session_key = key_map.get(provider.lower(), "openai")
    user_api_key = session.get(f"api_key_{session_key}", "").strip() or None

    try:
        endpoint = "query-agent" if agent_mode else "query"
        payload = {
            "session_id": session_id,
            "query": query,
            "provider": provider,
            "model_name": model_name,
            "domain": domain,
            "api_key": user_api_key,
            "namespace": namespace,
            "top_k": top_k,
            "use_reranker": use_reranker,
            "use_query_rewriter": use_query_rewriter,
            "content_types": content_types,
        }
        resp = requests.post(api(endpoint), json=payload, timeout=90)
        if resp.status_code == 200:
            result = resp.json()
            return jsonify({
                "answer": result.get("answer", "No answer."),
                "explanation": result.get("explanation", ""),
                "used_user_key": user_api_key is not None,
            })
        return jsonify({"error": f"API error {resp.status_code}: {resp.text[:300]}"}), 500
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/session-info", methods=["GET"])
def session_info():
    session_id = get_or_create_session()
    try:
        logs_r   = requests.get(f"{API_URL.rstrip('/')}/sessions/{session_id}/logs/", timeout=10)
        topics_r = requests.get(f"{API_URL.rstrip('/')}/sessions/{session_id}/topics/", timeout=10)
        logs   = logs_r.json()   if logs_r.status_code   == 200 else {}
        topics = topics_r.json() if topics_r.status_code == 200 else {}
        return jsonify({"session_id": session_id, "logs": logs, "topics": topics})
    except Exception as e:
        return jsonify({"error": str(e), "session_id": session_id}), 500


@app.route("/api/upload", methods=["POST"])
def upload():
    session_id = get_or_create_session()
    files     = request.files.getlist("files")
    topic     = request.form.get("topic", "")
    overwrite = request.form.get("overwrite", "false").lower() == "true"

    # The user's currently-selected provider + matching key — used for vision processing
    # (image descriptions, video frame captions) during upload.
    provider = request.form.get("provider", "").strip() or session.get("selected_provider", "openai")
    key_map  = {"openai": "openai", "anthropic": "anthropic", "gemini": "gemini", "google": "gemini"}
    provider_key_name = key_map.get(provider.lower(), "openai")
    api_key  = session.get(f"api_key_{provider_key_name}", "").strip() or None

    if not files:
        return jsonify({"status": "No files provided"}), 400
    ns = (session.get("user") or {}).get("namespace") or None
    try:
        files_to_send = [("files", (f.filename, f.read(), f.content_type)) for f in files]
        data = {"session_id": session_id, "overwrite": overwrite}
        if topic:    data["topic"]     = topic
        if provider: data["provider"]  = provider
        if api_key:  data["api_key"]   = api_key
        if ns:       data["namespace"] = ns  # per-user Pinecone namespace
        resp = requests.post(api("upload"), files=files_to_send, data=data, timeout=120)
        if resp.status_code == 200:
            result = resp.json()
            if "session_id" in result:
                session["session_id"] = result["session_id"]
            return jsonify({"status":     result.get("status", "Uploaded"),
                            "success":    result.get("success", True),
                            "session_id": session["session_id"],
                            "upload_ids": result.get("upload_ids", [])})
        return jsonify({"status": f"Error {resp.status_code}", "success": False, "upload_ids": []}), 500
    except Exception as e:
        return jsonify({"status": str(e)}), 500


@app.route("/api/website", methods=["POST"])
def process_website():
    session_id = get_or_create_session()
    url = request.json.get("url","")
    if not url:
        return jsonify({"status": "No URL provided"}), 400
    try:
        resp = requests.post(api("website"), json={"url": url, "session_id": session_id}, timeout=120)
        return jsonify({"status": resp.json().get("status","Done"), "session_id": session_id})
    except Exception as e:
        return jsonify({"status": str(e)}), 500


@app.route("/api/directory", methods=["POST"])
def process_directory():
    session_id = get_or_create_session()
    dp = request.json.get("directory_path","")
    if not dp:
        return jsonify({"status": "No path provided"}), 400
    try:
        resp = requests.post(api("directory"), json={"directory_path": dp, "session_id": session_id}, timeout=120)
        return jsonify({"status": resp.json().get("status","Done"), "session_id": session_id})
    except Exception as e:
        return jsonify({"status": str(e)}), 500


@app.route("/api/s3", methods=["POST"])
def process_s3():
    session_id = get_or_create_session()
    try:
        resp = requests.post(api("s3"), json={**request.json, "session_id": session_id}, timeout=120)
        return jsonify(resp.json())
    except Exception as e:
        return jsonify({"status": str(e)}), 500


@app.route("/api/upload-status/<upload_id>", methods=["GET"])
def get_upload_status(upload_id):
    try:
        base = API_URL.strip().rstrip("/")
        resp = requests.get(f"{base}/upload-status/{upload_id}", timeout=10, allow_redirects=True)
        return jsonify(resp.json()), resp.status_code
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/call-support", methods=["POST"])
def call_support():
    """
    Proxy route for the support widget's 'Call Me' button.
    Forwards phone_number to twili.py's /make-call endpoint.
    The Twilio backend URL (ngrok) lives in TWILIO_BACKEND_URL env var
    and is NEVER exposed to the browser — the user only ever sees /api/call-support.
    """
    twilio_backend = os.getenv("PUBLIC_URL", "").strip().rstrip("/")
    if not twilio_backend:
        return jsonify({"error": "Support service is not configured. Please contact admin."}), 503

    data         = request.get_json(silent=True) or {}
    phone_number = data.get("phone_number", "").strip()
    if not phone_number:
        return jsonify({"error": "phone_number is required"}), 400

    try:
        resp = requests.post(
            f"{twilio_backend}/make-call",
            json={"phone_number": phone_number},
            timeout=15,
        )
        return jsonify(resp.json()), resp.status_code
    except Exception as e:
        logger.error(f"[call-support] proxy error: {e}")
        return jsonify({"error": "Support service unreachable. Please try again later."}), 503


@app.route("/api/db-files", methods=["GET"])
def get_db_files():
    """
    Return all files currently stored in the Pinecone vector indexes,
    grouped by content type. Used to populate the sidebar DB panel.
    Each entry: {filename, content_type, chunk_count, session_id}
    """
    session_id = get_or_create_session()
    ns = (session.get("user") or {}).get("namespace") or None
    try:
        params = {"session_id": session_id}
        if ns: params["namespace"] = ns
        resp = requests.get(
            f"{API_URL.rstrip('/')}/db-files/",
            params=params,
            timeout=15
        )
        if resp.status_code == 200:
            return jsonify(resp.json())
        return jsonify({"files": [], "error": f"Backend {resp.status_code}"}), 200
    except Exception as e:
        return jsonify({"files": [], "error": str(e)}), 200



    session_id = get_or_create_session()
    try:
        resp = requests.post(api("reset"), data={"session_id": session_id}, timeout=30)
        return jsonify(resp.json())
    except Exception as e:
        return jsonify({"status": str(e)}), 500


@app.route("/api/save-keys", methods=["POST"])
def save_keys():
    data = request.json or {}
    for provider in ["openai", "anthropic", "gemini", "openrouter"]:
        val = data.get(provider, "").strip()
        if val:
            session[f"api_key_{provider}"] = val
    # Persist whichever provider the user currently has active,
    # so the upload route knows which key to use for vision processing.
    if data.get("selected_provider"):
        session["selected_provider"] = data["selected_provider"].strip().lower()
    return jsonify({"status": "saved"})


@app.route("/api/get-key-status", methods=["GET"])
def get_key_status():
    return jsonify({p: bool(session.get(f"api_key_{p}")) for p in ["openai","anthropic","gemini","openrouter"]})




# ─────────────────────────────────────────────────────────────────────────────
# AUTH ROUTES — login / register / logout / current user
# ─────────────────────────────────────────────────────────────────────────────

def get_current_user():
    """Return current user dict from Flask session, or None if not logged in."""
    return session.get("user")


def require_login():
    """Return error response if not logged in, else None."""
    if not get_current_user():
        from flask import redirect, url_for
        return redirect(url_for("login_page"))
    return None


@app.route("/login")
def login_page():
    if session.get("user"):
        from flask import redirect, url_for
        return redirect(url_for("index"))
    return render_template_string(AUTH_TEMPLATE, mode="login")


@app.route("/register")
def register_page():
    if session.get("user"):
        from flask import redirect, url_for
        return redirect(url_for("index"))
    return render_template_string(AUTH_TEMPLATE, mode="register")


@app.route("/api/auth/register", methods=["POST"])
def api_register():
    data = request.json or {}
    username = data.get("username", "").strip()
    email    = data.get("email", "").strip().lower()
    password = data.get("password", "")
    if not username or not email or not password:
        return jsonify({"error": "All fields are required"}), 400
    try:
        resp = requests.post(
            f"{API_URL.rstrip('/')}/auth/register",
            json={"username": username, "email": email, "password": password},
            timeout=10
        )
        data = resp.json()
        if resp.status_code == 200:
            session["user"] = {"user_id": data["user_id"], "username": data["username"],
                               "email": data["email"], "namespace": data["namespace"]}
            session["session_id"] = str(uuid.uuid4())
            return jsonify({"ok": True, "user": session["user"]})
        return jsonify({"error": data.get("detail", "Registration failed")}), resp.status_code
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/auth/login", methods=["POST"])
def api_login():
    data = request.json or {}
    email    = data.get("email", "").strip().lower()
    password = data.get("password", "")
    if not email or not password:
        return jsonify({"error": "Email and password are required"}), 400
    try:
        resp = requests.post(
            f"{API_URL.rstrip('/')}/auth/login",
            json={"email": email, "password": password},
            timeout=10
        )
        rdata = resp.json()
        if resp.status_code == 200:
            session["user"] = {"user_id": rdata["user_id"], "username": rdata["username"],
                               "email": rdata["email"], "namespace": rdata["namespace"]}
            session["session_id"] = str(uuid.uuid4())
            return jsonify({"ok": True, "user": session["user"]})
        return jsonify({"error": rdata.get("detail", "Login failed")}), resp.status_code
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/auth/logout", methods=["POST"])
def api_logout():
    session.clear()
    return jsonify({"ok": True})


@app.route("/api/auth/me", methods=["GET"])
def api_me():
    user = get_current_user()
    if not user:
        return jsonify({"error": "Not logged in"}), 401
    return jsonify(user)

